var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"회장, 여기가 정말 알렌 선생님이 사는 곳 맞아?","JPN":"会長、本当にここがアレン先生の家なの？","ENG":"So, Yen, is this really where Mr. Birmingham lives?","TWN":"會長，艾倫老師真的住在這裡沒錯嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 알렌 선생님과 함께 퇴근한 적 있는 교직원 분들에게도 확인 받았어요.","JPN":"はい、アレン先生と一緒に退勤したことがある職員の方にも確認いただきました。","ENG":"Yes. I even confirmed it with a faculty member who used to share a commute with him.","TWN":"是的，我們有和曾經跟艾倫老師一起下班的教職員確認過。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으음, 난 원룸에만 살아 봐서 잘 모르겠는데…….","JPN":"ううん、私はワンルームでしか暮らしたことがないからよくわからないけど……","ENG":"Hmm, I've only lived in a hole in the wall so I wouldn't know…","TWN":"嗯，我只住過套房所以不太清楚……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알렌 선생님이 혹시 엄청난 부자인 거 아냐?","JPN":"アレン先生って、もしかしたらとんでもないお金持ちなのかな？","ENG":"But could it be because Mr. Birmingham's super rich?","TWN":"請問艾倫老師是大富翁嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 숲이 부자들의 개인용 사냥터 같은 곳일 수도 있잖아.","JPN":"この森がお金持ちの個人用狩猟場みたいな場所かもしれないでしょ。","ENG":"This forest might be just a private hunting ground for rich folks.","TWN":"這片森林你說是有錢人專屬的狩獵場我也相信啊！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아무리 부자라고 해도, 도심 인근에 이런 국립공원 규모의 사유지를 보유하긴 어려워요.","JPN":"いくら大富豪とはいえ、都心近辺でこのような\\n国立公園規模の私有地を保有するのは不可能でしょう。","ENG":"Even the most affluent person would have trouble maintaining such an expanse of nature so close to the city.","TWN":"再怎麼有錢，也很難在市中心擁有像這樣如國家公園般的私人土地。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"무엇보다 이 숲은 도시 관리국이 제공하는 지도에도 나와 있지 않아요.","JPN":"何より、この森は都市管理局が提供する地図に載っていません。","ENG":"Most of all, this forest doesn't appear on the maps provided by the City Management.","TWN":"更何況，這片森林並沒有出現在城市管理局提供的地圖上。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지형 정보를 분석하려고 했지만, 데이터베이스에 대조군이 없다고 하더군요.","JPN":"地形情報を分析しようとしましたが、データベースにないようです。","ENG":"We tried to analyze the terrain, but the database could not find any comparable matches.","TWN":"原本是想分析地形資料的，但資料庫中沒有對照組。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……확실히, 수상하네.","JPN":"……確かに怪しいね。","ENG":"That definitely sounds fishy…","TWN":"果然……很可疑！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"수상한 건 그게 다가 아니야!","JPN":"怪しいのはそれだけじゃないの！","ENG":"That's not all!","TWN":"可疑的地方不只是這樣而已！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아까 그 침식체들도 그래. 우리가 여기 오자마자 갑자기 공격해 왔거든.","JPN":"さっきの侵食体もそう。私たちがここに着いた途端、いきなり襲いかかってきたの。","ENG":"Remember those C.O.s? They attacked us as soon as we got here.","TWN":"剛剛那些侵蝕體也是，我們一抵達這裡就突然來攻擊我們。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니 미카 넌 여기 왜 온 거야? 싸움은 싫어하지 않았어?","JPN":"そういえば、ミカはどうしてここに来たの？　戦闘は苦手なんじゃなかった？","ENG":"Come to think of it, what are you doing here, Mika? I thought you hated fighting.","TWN":"說到這個，米卡，你來這裡幹嘛？你不是討厭打打殺殺嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그게……. 학생 정보를 확인해 보니까 레이 선배 주소도 여기더라고.","JPN":"それが……生徒情報を照会したらレイ先輩の住所もここだったの。","ENG":"Well... According to the student database, Ray's home is registered to this address as well.","TWN":"因為……我查看學生資料後，發現雷伊前輩的地址也是在這裡。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"레이 선배도?","JPN":"レイ先輩も？","ENG":"Even Ray?","TWN":"雷伊前輩也住這裡？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응. 혹시라도 무슨 오해가 있을지도 모르잖아.","JPN":"うん。もしかしたら何かの間違いかもしれないでしょ？","ENG":"Yeah. Maybe there's been some kind of mix-up.","TWN":"對，這當中可能有什麼誤會。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"레이 선배가 사람을 해쳤을 거라고는 도저히 믿기지 않아서……. 회장님을 따라 온 거야.","JPN":"レイ先輩が人を傷つけたなんてとても信じられなくて……だから会長についてきたの。","ENG":"I refuse to believe that Ray is capable of hurting anyone… So, I followed the President here.","TWN":"我不相信雷伊前輩會做出傷害的事……所以才跟著會長過來。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그랬구나…….","JPN":"そうだったんだ……","ENG":"I see…","TWN":"原來是這樣……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흐암……. 다들 잘 들려?","JPN":"ふあぁー……みんな、聞こえる？","ENG":"*Yawn…* Can y'all hear me?","TWN":"哈啊……大家有聽到嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스? 무슨 일인가요?","JPN":"イーディス？　どうしましたか？","ENG":"Edith? What is it?","TWN":"伊蒂絲？你怎麼會來？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"으응. 보안 담당으로서 새로운 정보를 입수했거든.","JPN":"うーんとね、セキュリティ担当として新しい情報を入手したんだ。","ENG":"Well… Being in charge of security, I managed to score some new intel.","TWN":"嗯…我身為安全負責人，有收到新的情資。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"관리국에서 감찰 나온 사람들이 알렌 선생님의 서류 분석을 방금 막 끝냈어.","JPN":"管理局の監察官がアレン先生の書類分析をたった今終わらせたって。","ENG":"The inspectors from the Administration just finished analyzing Mr. Birmingham's records.","TWN":"管理局的調查人員分析艾倫老師的資料後發現…"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그런데 그거…… 전부 거짓말이래.","JPN":"どうもそれが……全部嘘だったらしい。","ENG":"And it turns out… it's all fake.","TWN":"那些……全都是假的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"거짓말?","JPN":"嘘？","ENG":"What do you mean, fake?","TWN":"假的？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"말 그대로야. 가족 관계도, 경력도 전부 그럴싸하게 적어 둔 가짜였어.","JPN":"言葉どおりだよ。家族関係も経歴も、全部それらしく書いた偽物だった。","ENG":"I mean it literally. All his family information and experience were completely forged.","TWN":"對，都是假的，無論是他的家人、履歷，雖然寫得跟真的一樣，但全都是假的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"감찰 나온 사람들이 주변인들 대상으로 대면 질의도 해 봤는데…….","JPN":"監察官が周りの人を対象に質疑応答もしたみたいだけど……","ENG":"They even interviewed his acquaintances to be sure…","TWN":"調查人員也有詢問他周圍的人……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"알렌 선생님이 언제부터 학교에 재직했는지 아는 사람이 아무도 없대.","JPN":"アレン先生がいつから学校に在職していたのか、知っている人が誰もいないって。","ENG":"But apparently no one knew how long Allen Birmingham had been working at the Academy.","TWN":"但都沒有人知道艾倫老師是何時開始在學院任教的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"어느날 갑자기 그 자리에 있었던 것처럼 말야.","JPN":"ある日突然現れたかのようにね。","ENG":"It's as if he just appeared out of thin air one day.","TWN":"好像他突然就出現在那個位置上一樣。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그리고 지금까지 아무도 의심하지 않았다는 거군요.","JPN":"そして、今まで誰も疑っていなかったということですね。","ENG":"And no one questioned anything about it until now.","TWN":"而且竟然也沒有任何人對他產生懷疑。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"우리도 그랬는걸? 다른 사람들도 마찬가지 아니었을까?","JPN":"私たちも疑問に思ってなかったでしょ？　他の人も同じだったんだね。","ENG":"We weren't any different. I'm sure it was the same with everyone else.","TWN":"我們尚且如此，更何況是其他人呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"하암…….. 그럼 다 알려 줬으니까 난 이제 다시 자러 갈게.","JPN":"ふああ……それじゃあ、共有事項は以上だから私はお布団の中に戻るね。","ENG":"*Yawn…* Well, I've told you all there was to say. I'm gonna go back to sleep now.","TWN":"哈啊……我話說完了，要去睡回籠覺了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"오늘은 12시간도 못 잤거든……. 피곤해 죽겠어…….","JPN":"今日は12時間しか寝てなくて……疲れちゃった……","ENG":"I barely slept 12 hours today… I'm pooped…","TWN":"我今天沒睡滿12小時欸……睏死我了……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그럼 안녕~","JPN":"じゃあね。","ENG":"See ya…","TWN":"走囉～"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다음 할 일이 정해진 것 같네.","JPN":"次にやるべきことが決まったね。","ENG":"I guess we know what to do next then.","TWN":"看來有些事需要弄清楚才行。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 이 숲 너머에 해답이 숨어 있기를 바랄 수 밖에요.","JPN":"はい。この森の向こうにその答えがあることを願います。","ENG":"Indeed. Let's just hope we'll find some answers behind this forest.","TWN":"是，希望答案就藏在森林的那一邊。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아까 그 침식체들이 다가 아니었나 본데.","JPN":"さっきの侵食体で全部じゃなかったみたいね。","ENG":"Looks like we weren't done with the C.O.s earlier.","TWN":"剛剛那些侵蝕體似乎不是全部，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"다른 녀석들이 더 숨어 있었던 것 같아.","JPN":"他のやつらも隠れていたみたい。","ENG":"I guess there were some more in hiding.","TWN":"應該還有其他藏起來的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"지금부턴 내가 앞장설게. 지원 부탁해.","JPN":"ここからは私が先陣を切るから、支援をお願い。","ENG":"I'll lead the way from here. Cover me.","TWN":"接下來由我帶頭，你們掩護我！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"레이 선배가 나쁜 사람은 아니라고 생각하지만…….","JPN":"レイ先輩が悪い人とは思えないけど……","ENG":"I don't think Ray would do anything so terrible…","TWN":"雖然我不認為雷伊前輩是壞人……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"진실은 직접 만나서 물어 보는 게 확실하겠지.","JPN":"真実は直接会って聞くのが確かだよね。","ENG":"But I guess I should ask him myself to be sure.","TWN":"但答案還是要問本人才知道。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};